patterns.codeBlock:
// BEFORE (wrong)
class Foo {
    int x;
}  // missing semicolon after class

// AFTER (correct)
class Foo {
    int x;
};  // semicolon required after class definition

// Use static_cast for safe conversions:
int i = static_cast<int>(doubleValue);

// For polymorphic types:
Derived* d = dynamic_cast<Derived*>(basePtr);

// Use #pragma once (modern):
#pragma once
class MyClass { };

// Or traditional include guards:
#ifndef MY_CLASS_H
#define MY_CLASS_H
class MyClass { };
#endif

#include <vector>    // for std::vector
#include <string>    // for std::string
#include <map>       // for std::map

// Make the conversion explicit:
int count = static_cast<int>(doubleValue);  // acknowledge truncation

// Or use the wider type:
size_t index = container.size();  // instead of int index

// In header: declare only
extern int globalVar;
inline void helperFunc() { }

// In one .cpp file: define
int globalVar = 42;

// BEFORE (dangerous)
int* p = new int(42);
delete p;
delete p;  // double free!

// AFTER (safe with smart pointer)
auto p = std::make_unique<int>(42);
// automatically freed when p goes out of scope

// BEFORE (dangerous)
char buf[10];
strcpy(buf, longString);  // overflow!

// AFTER (safe)
std::string buf = longString;  // dynamic, safe

// Or with bounds checking:
char buf[10];
strncpy(buf, longString, sizeof(buf) - 1);
buf[sizeof(buf) - 1] = '\0';

// BEFORE (wrong)
class Base {
public:
    virtual void foo();
    ~Base();  // non-virtual!
};

// AFTER (correct)
class Base {
public:
    virtual void foo();
    virtual ~Base() = default;  // virtual destructor
};
